  ('fire-eq-tech-moex-03210', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，何者為公共危險物品等場所之第三種滅火設備？', '["水霧、泡沫、二氧化碳或乾粉滅火設備", "自動撒水設備", "大型滅火器", "室內或室外消防栓設備"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03211', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，第五種滅火設備有關核算滅火效能值，下列何者錯誤？', '["8公升之消防專用水桶，每3個為1滅火效能值", "水槽每80公升為1.5滅火效能值", "乾燥砂每50公升為0.5滅火效能值", "膨脹蛭石或膨脹珍珠岩每100公升為1滅火效能值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03212', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，下列何者符合一般滅火困難場所之要求？', '["公共危險物品製造場所總樓地板面積在400平方公尺以上未滿1000平方公尺者", "公共危險物品數量達管制量10倍以上未滿100倍者", "室內儲存場所總樓地板面積在250平方公尺以上者", "室內儲存場所儲存公共危險物品數量達管制量10倍以上未滿250倍者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03213', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」之規定，各類場所之管理權人，應於檢修完成後多少 日內，分別填具消防安全設備檢修申報表及檢附消防安全設備檢修報告書，向當地消防機關申報？', '["5", "10", "15", "20"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03214', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，下列有關管理權人申報其檢修結果之期限敘述何 者正確？', '["甲類場所者，每半年1次，即每年6月30日及12月31日前申報", "甲類以外場所，每年1次，即每年11月30日前申報", "每次檢修時間之間隔，甲類場所不得少於6個月", "每次檢修時間之間隔，甲類以外之場所不得少於12個月"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03215', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」規定，下列對消防幫浦之敘述何者錯誤？', '["在額定出水量150%時，其軸動力不得超過馬達額定輸出馬力之120%", "幫浦在啟動時其軸承不得發生過熱，噪音或異常振動現象", "應標示製造廠商名稱或廠牌標誌", "全閉揚程應為性能曲線上全揚程之140%以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03216', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」規定，消防幫浦之電動機，應符合下列何項 規定？', '["使用單向誘導馬達或低壓三相誘導鼠籠式電動機或2KV以上之三相誘導鼠籠式電動機", "輸出功率11KW以上時，不得使用直接啟動方式", "在額定輸出連續運轉4小時後，不得發生異狀", "在超過額定輸出之20% 輸出力運轉1小時，仍不致發生障礙，引起過熱現象"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03217', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」規定，消防幫浦本體必須能耐最高水壓幾倍以 上，且加壓多少分鐘後，各部位仍無洩漏現象才算合格？', '["水壓3倍，且加壓1分鐘", "水壓3倍，且加壓3分鐘", "水壓1.5倍，且加壓1分鐘", "水壓1.5倍，且加壓3分鐘"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03218', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「排煙設備用閘門認可基準」規定，防火閘門熱感應裝置之額定溫度應在幾度之間？', '["101~157℃", "111~167℃", "121~177℃", "141~197℃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03219', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「緩降機認可基準」規定，移動式緩降機係指調速器之重量在多少公斤以下，於使用時以安全扣環確 實安裝在支固器具上之緩降機？', '["5", "10", "15", "20"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
